module mux(input select_1, input select_0, input in_0, input in_1, input in_2, input in_3, output reg out);
always @(*) begin
  if (!select_1 && !select_0) out = in_0;
  else if (!select_1 && select_0) out = in_1;
  else if (select_1 && !select_0) out = in_2;
  else if (select_1 && select_0) out = in_3;
end
endmodule
